import React, { useState, useEffect } from "react";

import ModuleSideNav from "../../../components/Users/ModuleSideNav.jsx";
import SideBar from '../../../components/social/SideBar';
import TopBar from '../../../components/social/TopBar';
import "bootstrap/dist/css/bootstrap.min.css";
import {
  SectionWrapper,
  Wrapper,
} from "../../../components/Styles/MainHeadStyles.js";
import { DataRoomSection } from "../../../components/Styles/DataRoomStyle.js";
import { BackButton } from "../../../components/Styles/GlobalStyles.js";
import { ArrowLeft, Plus, X } from "lucide-react";
import axios from "axios";
import { useNavigate, useParams } from "react-router-dom";
import { API_BASE_URL } from "../../../config/config.js";
import { Table } from "react-bootstrap";
export default function AddNewInvestor() {
  const navigate = useNavigate();
  const storedUsername = localStorage.getItem("SignatoryLoginData");
  const userLogin = JSON.parse(storedUsername);
  const access_token = userLogin?.access_token;
  const [spinners, setspinnsers] = useState(false);
  const [message, setmessage] = useState("");
  const [errr, seterrr] = useState(false);
  const [editInvestor, seteditInvestor] = useState("");
  const { id } = useParams();
  const [investortype, setinvestortype] = useState("");
  const [ClientIP, setClientIP] = useState("");
  const [showInvestorModal, setShowInvestorModal] = useState(false);
  const [investorsList, setInvestorsList] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectAll, setSelectAll] = useState(false);
  const [selectedInvestors, setSelectedInvestors] = useState([]);

  var apiURL = API_BASE_URL + "api/user/investor/";
  document.title = "Investor Report Form";
  // Function to fetch investors
  const fetchInvestorsList = async () => {
    const formData = {
      company_id: userLogin.companies[0].id,
    };
    try {
      const generateRes = await axios.post(
        apiURL + "getInvestors",
        formData,
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
            'Authorization': `Bearer ${access_token}`,
          },
        }
      );

      setInvestorsList(generateRes.data.data);
    } catch (err) {
      console.error("Error generating summary", err);
    }
  };
  const handleSelectInvestor = (investorId) => {
    setSelectedInvestors(prev => {
      if (prev.includes(investorId)) {
        return prev.filter(id => id !== investorId);
      } else {
        return [...prev, investorId];
      }
    });
  };

  // Handle select all
  const handleSelectAll = () => {
    if (selectAll) {
      setSelectedInvestors([]);
    } else {
      setSelectedInvestors(investorsList.map(investor => investor.id));
    }
    setSelectAll(!selectAll);
  };
  // Open modal and fetch investors
  const handleOpenInvestorModal = () => {
    setShowInvestorModal(true);
    fetchInvestorsList();
  };
  // Handle send invitation
  const handleSendInvitation = async (selectedInvestorIds) => {
    try {
      setLoading(true);

      // Get the selected investors data
      const selectedInvestorsData = investorsList.filter(investor =>
        selectedInvestorIds.includes(investor.id)
      );

      // Get investor IDs array
      const investorIds = selectedInvestorIds;


      // Prepare data to send
      const invitationData = {
        investor_ids: investorIds, // Array of IDs
        investors: selectedInvestorsData, // Full data if needed
        company_id: userLogin?.companies?.[0]?.id,
        sent_by: userLogin?.id,
        created_by_id: userLogin.id,
        created_by_role: userLogin.role,
        id: null,
        ip_address: ClientIP,
      };

      // Call your API to send invitation
      const response = await axios.post(`${apiURL}sendInvitation`, invitationData, {
        headers: {
          Accept: "application/json",
          "Content-Type": "application/json",
          'Authorization': `Bearer ${access_token}`,
        },
      });

      if (response.data.status === 1) {
        //toast.success(`Invitation sent to ${investorIds.length} investor(s) successfully!`);
        setTimeout(() => {
          fetchInvestorsList();
          setSelectedInvestors([])
          setShowInvestorModal(false);
          setmessage('');
        }, 3500);
        setSelectAll(false);
        setmessage(response.data.message);
      } else {
        seterrr(true);
        setmessage(response.data.message);
      }

    } catch (error) {
      console.error("Error sending invitation:", error);
      // toast.error(error.response?.data?.message || "Error sending invitations");
    } finally {
      setLoading(false);
    }
  };
  // Multiple investors state
  const [investors, setInvestors] = useState([{
    email: "",
    first_name: "",
    last_name: "",
    screen_name: ""
  }]);



  useEffect(() => {
    if (id) {
      getInvestoreditlist();
    }
  }, []);

  useEffect(() => {
    const getIP = async () => {
      try {
        const res = await fetch("https://api.ipify.org?format=json");
        const data = await res.json();
        setClientIP(data.ip);
      } catch (error) {
        console.error("Failed to fetch IP", error);
      }
    };

    getIP();
  }, []);

  const getInvestoreditlist = async () => {
    const formData = {
      company_id: userLogin.companies[0].id,
      id: id,
    };
    try {
      const generateRes = await axios.post(
        apiURL + "getInvestoreditlist",
        formData,
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
            'Authorization': `Bearer ${access_token}`,
          },
        }
      );
      if (generateRes.data.results.length > 0) {
        setinvestortype(generateRes.data.results[0].investorType);
        seteditInvestor(generateRes.data.results[0]);
      } else {
        navigate("/crm/investor-directory");
      }
    } catch (err) {
      console.error("Error generating summary", err);
    }
  };
  function formatCurrentDate(input) {
    if (!input) return "";

    const date = new Date(input);

    if (Number.isNaN(date.getTime())) return "";

    const months = [
      "Jan", "Feb", "Mar", "Apr", "May", "Jun",
      "Jul", "Aug", "Sep", "Oct", "Nov", "Dec",
    ];

    const day = date.getDate();
    const month = months[date.getMonth()];
    const year = date.getFullYear();

    const getOrdinal = (n) => {
      if (n >= 11 && n <= 13) return "th";
      switch (n % 10) {
        case 1: return "st";
        case 2: return "nd";
        case 3: return "rd";
        default: return "th";
      }
    };

    return `${month} ${day}${getOrdinal(day)}, ${year}`;
  }
  // Handle input change for each investor
  const handleInvestorChange = (index, field, value) => {
    const newInvestors = [...investors];
    newInvestors[index][field] = value;
    setInvestors(newInvestors);
  };

  // Add new investor form
  const addMoreInvestor = () => {
    setInvestors([...investors, {
      email: "",
      first_name: "",
      last_name: "",
      screen_name: ""
    }]);
  };

  // Remove investor form
  const removeInvestor = (index) => {
    if (investors.length > 1) {
      setInvestors(investors.filter((_, i) => i !== index));
    }
  };

  // Submit all investors
  const handleSubmit = async (e) => {
    e.preventDefault();
    setspinnsers(true);

    try {
      // Validate all investors first
      const validInvestors = [];
      const validationErrors = [];

      investors.forEach((investor, index) => {
        if (!investor.email || !investor.first_name || !investor.last_name) {
          validationErrors.push(`Form ${index + 1}: All fields (email, first name, last name) are required`);
        } else {
          validInvestors.push({
            email: investor.email,
            first_name: investor.first_name,
            last_name: investor.last_name,
            company_id: userLogin.companies[0].id,
            created_by_id: userLogin.id,
            created_by_role: userLogin.role,
            id: editInvestor.id || null,
            ip_address: ClientIP,
          });
        }
      });

      // If there are validation errors, show them and return
      if (validationErrors.length > 0) {
        setspinnsers(false);
        seterrr(true);
        setmessage(`Validation failed: ${validationErrors.join(" | ")}`);
        setTimeout(() => setmessage(""), 4000);
        return;
      }

      // If no valid investors, return
      if (validInvestors.length === 0) {
        setspinnsers(false);
        seterrr(true);
        setmessage("No valid investors to add");
        setTimeout(() => setmessage(""), 4000);
        return;
      }

      // Send all investors in one request
      const generateRes = await axios.post(
        apiURL + "Addinvenstor",
        validInvestors,
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
            'Authorization': `Bearer ${access_token}`,
          },
        }
      );



      setspinnsers(false);

      // Handle response based on status
      if (generateRes.data.status === 1) {
        // All investors added successfully
        const successCount = generateRes.data.summary?.success || validInvestors.length;
        seterrr(false);
        setmessage(`Investor successfully added!`);
        setTimeout(() => {
          window.location.reload()
          // navigate("/crm/investor-directory");
        }, 2500);
      }
      else if (generateRes.data.status === "partial") {
        // Partial success - collect all errors
        const successCount = generateRes.data.summary?.success || 0;
        const errorMessages = [];

        // Loop through results to find errors
        if (generateRes.data.results && Array.isArray(generateRes.data.results)) {
          generateRes.data.results.forEach(result => {
            // Check if this result has status 0 (error)
            if (result.status === 0 && result.message) {
              errorMessages.push(result.message);
            }
          });
        }

        if (errorMessages.length > 0) {
          seterrr(true);
          setmessage(`${successCount} added, ${errorMessages.length} failed: ${errorMessages.join(" | ")}`);
        } else {
          seterrr(false);
          setmessage(`${successCount} investor(s) successfully added!`);
        }
      }
      else if (generateRes.data.status === 0) {
        // All failed
        seterrr(true);
        setmessage(`Failed: ${generateRes.data.message}`);
      }

      setTimeout(() => {
        setmessage("");
      }, 4000);

    } catch (err) {
      console.error("Error in handleSubmit:", err);
      setspinnsers(false);
      seterrr(true);
      setmessage(err.response?.data?.message || "Error occurred while submitting");
      setTimeout(() => setmessage(""), 4000);
    }
  };

  const handleBackClick = () => {
    navigate("/crm/investor-directory");
  };

  return (
    <>
      <main>
        <div className='d-flex align-items-start gap-0'>
          <SideBar />
          <div className='d-flex flex-grow-1 flex-column gap-0'>
            <TopBar />
            <section className='px-md-3 py-4'>
              <div className='container-fluid'>
                <div className='row gy-4'>
                  <div className='col-md-12 order-1 order-md-0'>
                    <SectionWrapper className="d-block p-md-4 p-3">
                      {message && (
                        <p className={errr ? " mt-3 error_pop" : "success_pop mt-3"}>
                          {message}
                        </p>
                      )}
                      <div className="container-fluid">
                        <DataRoomSection className="d-flex flex-column gap-2">
                          <div className="titleroom d-flex justify-content-between align-items-center border-bottom pb-3">
                            <BackButton
                              type="button"
                              className="backbtn"
                              onClick={handleBackClick}
                            >
                              <ArrowLeft size={16} className="me-1" /> back
                            </BackButton>
                            <h4>
                              Add Investor
                            </h4>
                            <button
                              type="button"
                              className="btn btn-primary"
                              onClick={handleOpenInvestorModal}
                              style={{
                                backgroundColor: 'var(--primary)',
                                borderColor: 'var(--primary)',
                                padding: '8px 16px'
                              }}
                            >
                              View Investors List
                            </button>
                          </div>

                          <form onSubmit={handleSubmit}>
                            <div className="formlist">
                              {/* Multiple Forms */}
                              {investors.map((investor, index) => (
                                <div key={index} className="investor-form mb-4 p-3" style={{
                                  border: '1px solid #e0e0e0',
                                  borderRadius: '8px',
                                  backgroundColor: index % 2 === 0 ? '#f9f9f9' : '#fff'
                                }}>
                                  <div className="d-flex justify-content-between align-items-center mb-3">
                                    <h6 className="mb-0">Investor {index + 1}</h6>
                                    {investors.length > 1 && (
                                      <button
                                        type="button"
                                        className="btn btn-link text-danger p-0"
                                        onClick={() => removeInvestor(index)}
                                      >
                                        <X size={20} />
                                      </button>
                                    )}
                                  </div>

                                  <div className="row">
                                    {/* First Name */}
                                    <div className="col-6">
                                      <label className="d-block mt-3">
                                        <div className="d-flex align-items-center gap-2 mb-2">
                                          <h5>
                                            First Name{" "}
                                            <span style={{ color: "var(--primary)" }}>
                                              *
                                            </span>
                                          </h5>
                                        </div>
                                        <input
                                          className="form-control"
                                          type="text"
                                          placeholder="Enter first name..."
                                          value={investor.first_name}
                                          onChange={(e) => handleInvestorChange(index, 'first_name', e.target.value)}
                                          required
                                        />
                                      </label>
                                    </div>

                                    {/* Last Name */}
                                    <div className="col-6">
                                      <label className="d-block mt-3">
                                        <div className="d-flex align-items-center gap-2 mb-2">
                                          <h5>
                                            Last Name{" "}
                                            <span style={{ color: "var(--primary)" }}>
                                              *
                                            </span>
                                          </h5>
                                        </div>
                                        <input
                                          className="form-control"
                                          type="text"
                                          placeholder="Enter last name..."
                                          value={investor.last_name}
                                          onChange={(e) => handleInvestorChange(index, 'last_name', e.target.value)}
                                          required
                                        />
                                      </label>
                                    </div>
                                    {/* Email */}
                                    <div className="col-6">
                                      <label className="d-block mt-3">
                                        <div className="d-flex align-items-center gap-2 mb-2">
                                          <h5>
                                            Email{" "}
                                            <span style={{ color: "var(--primary)" }}>
                                              *
                                            </span>
                                          </h5>
                                        </div>
                                        <input
                                          className="form-control"
                                          type="email"
                                          placeholder="Enter email..."
                                          value={investor.email}
                                          onChange={(e) => handleInvestorChange(index, 'email', e.target.value)}
                                          required
                                        />
                                      </label>
                                    </div>




                                  </div>
                                </div>
                              ))}

                              {/* Add More Button */}
                              <button
                                type="button"
                                className="btn  mb-4"
                                onClick={addMoreInvestor}
                                style={{
                                  borderColor: 'var(--primary)',
                                  color: 'var(--primary)',
                                }}
                              >
                                <Plus size={18} className="me-2" />
                                Add More Investor
                              </button>

                              {/* Submit Button */}
                              <div className="d-flex justify-content-start align-items-center mt-3">
                                <input
                                  type="submit"

                                  className="global_btn ms-auto w-fit"
                                  value={`Submit ${investors.length > 1 ? `(${investors.length} investors)` : ''}`}

                                />
                                {spinners && (
                                  <div
                                    className="spinner-border text-light ms-2"
                                    role="status"
                                    style={{ width: "1.5rem", height: "1.5rem" }}
                                  >
                                    <span className="visually-hidden">
                                      Loading...
                                    </span>
                                  </div>
                                )}
                              </div>
                            </div>
                          </form>
                        </DataRoomSection>
                      </div>
                    </SectionWrapper>
                  </div>

                </div>
              </div>
            </section>
          </div>
        </div>
      </main>
      {showInvestorModal && (
        <div className="modal show d-block" tabIndex="-1" style={{ backgroundColor: 'rgba(0,0,0,0.5)' }}>
          <div className="modal-dialog modal-xl">
            <div className="modal-content">
              <div className="modal-header">
                <h5 className="modal-title">Investor List</h5>
                <button
                  type="button"
                  className="btn-close"
                  onClick={() => setShowInvestorModal(false)}
                />
              </div>
              <div className="modal-body">
                {loading ? (
                  <div className="text-center p-3">
                    <div className="spinner-border text-primary" role="status">
                      <span className="visually-hidden">Loading...</span>
                    </div>
                  </div>
                ) : investorsList.length === 0 ? (
                  <div className="text-center p-3 text-muted">
                    No investors found
                  </div>
                ) : (
                  <>
                    <Table striped bordered hover responsive>
                      <thead>
                        <tr>
                          <th style={{ width: '50px' }}>
                            <input
                              type="checkbox"
                              checked={selectAll}
                              onChange={handleSelectAll}
                            />
                          </th>
                          <th>Email</th>
                          <th>First Name</th>
                          <th>Last Name</th>
                          <th>Join Status</th>
                          <th>Join Date</th>
                        </tr>
                      </thead>
                      <tbody>
                        {investorsList.map((investor) => (
                          <tr key={investor.id}>
                            <td style={{ width: '50px' }}>
                              <input
                                type="checkbox"
                                checked={selectedInvestors.includes(investor.id)}
                                onChange={() => handleSelectInvestor(investor.id)}
                                disabled={investor.joinstatus !== null && investor.joinstatus !== undefined}
                                style={{
                                  cursor: investor.joinstatus !== null && investor.joinstatus !== undefined ? 'not-allowed' : 'pointer'
                                }}
                              />
                            </td>
                            <td>{investor.email}</td>
                            <td>{investor.first_name}</td>
                            <td>{investor.last_name}</td>
                            <td style={{
                              padding: '12px',
                              textAlign: 'center'
                            }}>
                              <span style={{
                                display: 'inline-block',
                                padding: '4px 12px',
                                borderRadius: '20px',
                                fontSize: '12px',
                                fontWeight: '600',
                                backgroundColor: investor.joinstatus === 'Yes'
                                  ? '#d1fae5'
                                  : investor.joinstatus === 'No'
                                    ? '#fee2e2'
                                    : '#e2e3e5',
                                color: investor.joinstatus === 'Yes'
                                  ? '#065f46'
                                  : investor.joinstatus === 'No'
                                    ? '#b91c1c'
                                    : '#383d41'
                              }}>
                                {investor.joinstatus === 'Yes'
                                  ? 'Yes'
                                  : investor.joinstatus === 'No'
                                    ? 'No'
                                    : 'N/A'}
                              </span>
                            </td>
                            <td>{investor.joinstatus === 'Yes' && investor.joined_at
                              ? formatCurrentDate(investor.joined_at)
                              : 'N/A'}</td>
                          </tr>
                        ))}
                      </tbody>
                    </Table>

                    {selectedInvestors.length > 0 && (
                      <div className="alert alert-info mt-3">
                        <strong>{selectedInvestors.length}</strong> investor(s) selected
                      </div>
                    )}
                  </>
                )}
              </div>
              <div className="modal-footer">
                <button
                  type="button"
                  className="btn btn-secondary"
                  onClick={() => setShowInvestorModal(false)}
                >
                  Close
                </button>

                {/* Send Invitation Button */}
                {selectedInvestors.length > 0 && (
                  <button
                    type="button"
                    className="btn btn-primary"
                    onClick={() => handleSendInvitation(selectedInvestors)}
                    style={{
                      backgroundColor: 'var(--primary)',
                      borderColor: 'var(--primary)'
                    }}
                  >
                    Send Invitation ({selectedInvestors.length})
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
}